CREATE TABLE `teach_courses` (`id` text PRIMARY KEY NOT NULL, `organization_id` text, `owner_id` text NOT NULL, `title` text NOT NULL, `subject` text NOT NULL, `locale` text DEFAULT 'fr' NOT NULL, `status` text DEFAULT 'draft' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`organization_id`) REFERENCES `organizations`(`id`), FOREIGN KEY (`owner_id`) REFERENCES `users`(`id`));
CREATE INDEX `teach_courses_owner_idx` ON `teach_courses` (`owner_id`);
CREATE INDEX `teach_courses_org_idx` ON `teach_courses` (`organization_id`);
CREATE TABLE `teach_enrollments` (`id` text PRIMARY KEY NOT NULL, `course_id` text NOT NULL, `user_id` text NOT NULL, `role` text NOT NULL, `status` text DEFAULT 'active' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `revoked_at` text, FOREIGN KEY (`course_id`) REFERENCES `teach_courses`(`id`), FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE INDEX `teach_enrollments_course_idx` ON `teach_enrollments` (`course_id`);
CREATE INDEX `teach_enrollments_user_idx` ON `teach_enrollments` (`user_id`);
CREATE UNIQUE INDEX `teach_enrollments_unique_idx` ON `teach_enrollments` (`course_id`,`user_id`,`role`);
CREATE TABLE `teach_modules` (`id` text PRIMARY KEY NOT NULL, `course_id` text NOT NULL, `title` text NOT NULL, `position` integer DEFAULT 0 NOT NULL, `status` text DEFAULT 'draft' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`course_id`) REFERENCES `teach_courses`(`id`));
CREATE INDEX `teach_modules_course_idx` ON `teach_modules` (`course_id`);
CREATE TABLE `teach_lessons` (`id` text PRIMARY KEY NOT NULL, `course_id` text NOT NULL, `module_id` text NOT NULL, `title` text NOT NULL, `position` integer DEFAULT 0 NOT NULL, `duration_minutes` integer DEFAULT 60 NOT NULL, `status` text DEFAULT 'draft' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`course_id`) REFERENCES `teach_courses`(`id`), FOREIGN KEY (`module_id`) REFERENCES `teach_modules`(`id`));
CREATE INDEX `teach_lessons_course_idx` ON `teach_lessons` (`course_id`);
CREATE INDEX `teach_lessons_module_idx` ON `teach_lessons` (`module_id`);
CREATE TABLE `learning_objectives` (`id` text PRIMARY KEY NOT NULL, `lesson_id` text NOT NULL, `notion` text NOT NULL, `prompt` text NOT NULL, `target_answer` text NOT NULL, `translation` text DEFAULT '' NOT NULL, `phonetic_help` text DEFAULT '' NOT NULL, `position` integer DEFAULT 0 NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`lesson_id`) REFERENCES `teach_lessons`(`id`));
CREATE INDEX `learning_objectives_lesson_idx` ON `learning_objectives` (`lesson_id`);
CREATE TABLE `learning_questions` (`id` text PRIMARY KEY NOT NULL, `objective_id` text NOT NULL, `prompt` text NOT NULL, `context_key` text NOT NULL, `kind` text DEFAULT 'primary' NOT NULL, `position` integer DEFAULT 0 NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`objective_id`) REFERENCES `learning_objectives`(`id`));
CREATE INDEX `learning_questions_objective_idx` ON `learning_questions` (`objective_id`);
CREATE TABLE `learning_hints` (`id` text PRIMARY KEY NOT NULL, `objective_id` text NOT NULL, `assistance_level` text NOT NULL, `content` text NOT NULL, `position` integer DEFAULT 0 NOT NULL, `exposes_target` integer DEFAULT false NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`objective_id`) REFERENCES `learning_objectives`(`id`));
CREATE INDEX `learning_hints_objective_idx` ON `learning_hints` (`objective_id`);
CREATE TABLE `learning_attempts` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `objective_id` text NOT NULL, `question_id` text NOT NULL, `submitted_question_id` text NOT NULL, `answer` text NOT NULL, `assistance_level` text NOT NULL, `answer_matches` integer DEFAULT false NOT NULL, `context_matched` integer DEFAULT false NOT NULL, `delayed_recall` integer DEFAULT false NOT NULL, `restarted_without_confusion` integer DEFAULT false NOT NULL, `transfer_demonstrated` integer DEFAULT false NOT NULL, `error_code` text DEFAULT 'none' NOT NULL, `confusion_code` text DEFAULT 'none' NOT NULL, `recall_delay_seconds` integer DEFAULT 0 NOT NULL, `response_time_ms` integer DEFAULT 0 NOT NULL, `resulting_state` text NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`), FOREIGN KEY (`objective_id`) REFERENCES `learning_objectives`(`id`), FOREIGN KEY (`question_id`) REFERENCES `learning_questions`(`id`));
CREATE INDEX `learning_attempts_user_idx` ON `learning_attempts` (`user_id`);
CREATE INDEX `learning_attempts_objective_idx` ON `learning_attempts` (`objective_id`);
CREATE INDEX `learning_attempts_question_idx` ON `learning_attempts` (`question_id`);
CREATE TABLE `learning_reminders` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `objective_id` text NOT NULL, `attempt_id` text NOT NULL, `cadence` text NOT NULL, `due_at` text NOT NULL, `status` text DEFAULT 'scheduled' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `completed_at` text, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`), FOREIGN KEY (`objective_id`) REFERENCES `learning_objectives`(`id`), FOREIGN KEY (`attempt_id`) REFERENCES `learning_attempts`(`id`));
CREATE INDEX `learning_reminders_user_due_idx` ON `learning_reminders` (`user_id`,`due_at`);
CREATE INDEX `learning_reminders_objective_idx` ON `learning_reminders` (`objective_id`);
CREATE TABLE `teach_checkpoints` (`user_id` text PRIMARY KEY NOT NULL, `lesson_id` text NOT NULL, `objective_id` text, `question_id` text, `mastery_state` text DEFAULT 'new' NOT NULL, `assistance_level` text DEFAULT 'wait' NOT NULL, `phase` text DEFAULT 'attempt' NOT NULL, `session_elapsed_seconds` integer DEFAULT 0 NOT NULL, `next_review_at` text, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`), FOREIGN KEY (`lesson_id`) REFERENCES `teach_lessons`(`id`), FOREIGN KEY (`objective_id`) REFERENCES `learning_objectives`(`id`), FOREIGN KEY (`question_id`) REFERENCES `learning_questions`(`id`));
CREATE TABLE `strength_observations` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `category` text NOT NULL, `statement` text NOT NULL, `evidence` text NOT NULL, `contradiction` text DEFAULT '' NOT NULL, `confidence_basis_points` integer DEFAULT 0 NOT NULL, `source_kind` text NOT NULL, `status` text DEFAULT 'pending_student_review' NOT NULL, `expires_at` text, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE INDEX `strength_observations_user_idx` ON `strength_observations` (`user_id`);
CREATE INDEX `strength_observations_status_idx` ON `strength_observations` (`status`);
CREATE TABLE `algoquest_learning_events` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `event_type` text NOT NULL, `artifact_ref` text NOT NULL, `purpose` text NOT NULL, `payload` text DEFAULT '{}' NOT NULL, `idempotency_key` text NOT NULL, `status` text DEFAULT 'pending' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE INDEX `algoquest_events_user_idx` ON `algoquest_learning_events` (`user_id`);
CREATE UNIQUE INDEX `algoquest_events_idempotency_idx` ON `algoquest_learning_events` (`user_id`,`idempotency_key`);
CREATE TABLE `growth_stories` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `publication_id` text, `domain` text NOT NULL, `title` text NOT NULL, `reflection` text NOT NULL, `evidence_ref` text DEFAULT '' NOT NULL, `visibility` text DEFAULT 'private' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`), FOREIGN KEY (`publication_id`) REFERENCES `publications`(`id`));
CREATE INDEX `growth_stories_user_idx` ON `growth_stories` (`user_id`);
CREATE INDEX `growth_stories_publication_idx` ON `growth_stories` (`publication_id`);
CREATE TABLE `teach_media_requests` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `kind` text NOT NULL, `source_ref` text NOT NULL, `duration_minutes` integer NOT NULL, `status` text DEFAULT 'prepared' NOT NULL, `requested_day` text NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE INDEX `teach_media_requests_quota_idx` ON `teach_media_requests` (`user_id`,`kind`,`requested_day`);
CREATE TABLE `teach_purpose_consents` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `purpose` text NOT NULL, `status` text DEFAULT 'granted' NOT NULL, `consent_version` text DEFAULT 'teach-v1' NOT NULL, `expires_at` text, `granted_at` text NOT NULL, `revoked_at` text, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE INDEX `teach_consents_user_idx` ON `teach_purpose_consents` (`user_id`);
CREATE UNIQUE INDEX `teach_consents_purpose_idx` ON `teach_purpose_consents` (`user_id`,`purpose`);
